var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"젠장. 기계라 그런지 능력이 먹통이잖아?","JPN":"くそ。機械だからか能力がまったく効かないじゃない。","ENG":"Damn, I guess my abilities aren't working because it's a machine.","TWN":"糟糕，我的能力好像對機械起不了作用？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님! 혹시 할아버님이 지닌 약점 같은 건 없나요?","JPN":"室長！　もしかしてお爺さんの弱点とかはないんですか？","ENG":"Chief! Does your grandfather have any weaknesses?","TWN":"室長！爺爺他有沒有什麼弱點？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님?","JPN":"室長？","ENG":"Chief?","TWN":"室長？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으… 할아버지가.","JPN":"うう……おじいちゃんが。","ENG":"Ugh... Grandpa.","TWN":"呃呃……爺爺。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정신 차리세요, 실장님! 지금 우울해져 있을 때가 아니라구요!","JPN":"しっかりしてください、室長！　今落ち込んでる場合じゃないです！","ENG":"Get it together, Chief! It's not the time to be depressed!","TWN":"振作一點，室長！現在不是沮喪的時候！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음, 정신교란계 능력이라니 과연 악당다운 능력이군!","JPN":"うむ、精神錯乱系の能力とは、まさに悪党らしい能力だな！","ENG":"Hmm. Mind-disruption abilities. Fitting for a villain!","TWN":"嗯，精神干擾，果然是壞蛋的能力啊！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자네의 극악무도함에 전방향 인식카메라조차 눈을 감지 못했다네!","JPN":"君の極悪非道さに全方位カメラさえも目をつぶることができなかったぞ！","ENG":"Even the multi-directional recognition camera is unable to close its eyes due to your utter wickedness!","TWN":"你窮凶極惡的行徑連我的這個全方位感知攝影鏡頭都無法閉上眼睛！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이것 보게나. 이터니움 합금 몸체조차 떨려오는 것이…!","JPN":"これを見てくれ。エタニウム合金の胴体すら震えて……！","ENG":"Look at this. Even this Eternium-fused body is shaking...!","TWN":"看看這個，我的永恆之金合金的身體都在因此而顫抖……！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"비상입니다, 유피. 제 완벽한 작전을 들켜버렸어요.","JPN":"非常事態です、ユピ。私の完璧な作戦がバレてしまいました。","ENG":"We're in trouble, Yuppie. Credere's perfect plan has been exposed.","TWN":"緊急情況，悠菲。克蕾妲莉的完美作戰計畫被發現了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"작전은 무슨. 주먹으로 친다고 저 철판에 구멍이라도 나겠어요?","JPN":"作戦ってなんですか。拳で叩いてもあの鉄板には穴一つ開きませんよ。","ENG":"What plan? Do you think you can make a dent in that steel plate with your fists?","TWN":"什麼作戰計畫啊。你是想用拳頭在那個鐵板上敲出洞來嗎！？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"물론이고 말고, 내 합금 몸체는 그런 작은 주먹으로는 흠집도 안 난다네.","JPN":"そうだとも、吾輩の合金胴体はそのような小さな拳では傷もつかないのだ。","ENG":"Of course not. Those small fists will not be able to make a scratch on my Eternium-fused body.","TWN":"哼，我的合金身體可不是那種小拳頭能留下痕跡的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그러니 이만 포기하고 순순히 투항하도록!","JPN":"だからもう諦めて素直に投降しろ！","ENG":"I suggest that you give up and surrender.","TWN":"所以現在放棄，乖乖投降吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으…!","JPN":"うう……！","ENG":"Ugh...!","TWN":"呃呃……！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"왜 내 말을 안 믿어주는 거야! 유피는 나쁜 사람이 아니라고 했잖아!","JPN":"どうして私の言葉を信じてくれないの！　ユピは悪い人じゃないって言ったのに！","ENG":"Why don't you believe me?! Yuppie isn't a bad person!","TWN":"為什麼爺爺不相信我！西格瑪都說過了，悠菲不是壞人！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"잘 듣게, 시그마. 인간은 상처를 감추기 위해 때론 거짓말을 하곤 한다네.","JPN":"よく聞くのだ、シグマ。人間は傷を隠すため、時には噓をつく。","ENG":"Listen, Sigma. Humans often lie to hide their scars.","TWN":"聽好了，西格瑪。人類有時候會為了掩蓋傷口而撒謊。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"쉽게 말해 저런 친구랑 놀면 안 된다는 뜻이지!","JPN":"わかりやすく言うと、あのような友人と親しくしてはいけない！","ENG":"In other words, you should not make friends with people like that!","TWN":"簡單來說，就是不可以和那種人玩！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아니야! 유피는 거짓말 같은 건 안 했는걸!","JPN":"違う！　ユピはウソなんかついてないもん！","ENG":"No! Yuppie didn't lie to me!","TWN":"不是的！悠菲沒有說謊！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"왜 내 친구한테 뭐라 해? 할아버지는 유피에 대해서 아무것도 모르잖아!","JPN":"なんで私の友だちに難癖をつけるの？　おじいちゃんはユピのこと、何も知らないんでしょう！","ENG":"Why are you so mean to my friend? You don't know anything about Yuppie!","TWN":"為什麼要說我朋友的壞話？爺爺你根本就不了解悠菲！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음. 범죄이력이라면 빠짐없이 얘기해 줄 수 있다네!","JPN":"うむ。だが犯罪歴ならすべて話してやれるのだ！","ENG":"Hmm. I can list all of her criminal records if you wish!","TWN":"嗯，如果你想聽犯罪記錄的話，我可以一五一十地告訴你！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유피는 나쁘지 않아! 전부 다 오해라구!","JPN":"ユピは悪くない！　全部誤解なの！","ENG":"Yuppie isn't a bad person! It's all a misunderstanding!","TWN":"悠菲才不是壞人！這全都是誤會！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"나보고 뭐든 부탁하라 했으면서… 정작 아무런 말도 안 믿어주고.","JPN":"どんなことでも頼りなさいって言ったくせに……なにも信じてくれないし。","ENG":"You told me I could count on you for anything... but you're not even listening to me.","TWN":"還說什麼西格瑪可以拜託爺爺任何事……結果爺爺根本都不相信西格瑪。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"할아버지 미워!!","JPN":"おじいちゃん、大嫌い！！","ENG":"I hate you, Grandpa!","TWN":"西格瑪討厭你，爺爺！！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};